MOD = 998244353

def power(x, p):
    if p < 0:
        return power(power(x, MOD - 2), -p)
    answer = 1
    x %= MOD
    while p:
        if p & 1:
            answer = answer * x % MOD
        x = x * x % MOD
        p >>= 1
    return answer

def solve_case(n):
    k = power(2, MOD - 2)
    l = n
    r = max(1, (n - 1) * 2)
    n0 = 0
    Q = []
    
    while l > 1:
        P = []
        l = (l + 1) // 2
        r //= 2
        s = n0
        
        for i in range(len(Q)):
            s = (s + Q[i] * power(power(k, -(1 << i)), r + 1)) % MOD
        
        P.append(((power(k, r + 1) * s - power(k, r)) % MOD + MOD) % MOD)
        
        for i in range(len(Q)):
            inv_term = power(power(k, 1 - (1 << (i + 1))) - 1, MOD - 2)
            pow_term = power(power(k, 1 - (1 << (i + 1))), r + 1)
            P[0] += inv_term * Q[i] % MOD * pow_term % MOD * k % MOD
            P.append(((MOD - Q[i] * k % MOD * inv_term % MOD) % MOD + MOD) % MOD)
        
        P[0] += (MOD - n0) * power(k, r + 1) % MOD
        
        for i in range(len(P)):
            P[i] %= MOD
        
        Q = P
        n0 += 2
    
    s = n0
    for i in range(len(Q)):
        s = (s + Q[i] * power(power(k, -(1 << i)), 1)) % MOD
    
    return s

